#include <stdio.h>
#include <stdint.h>
#include <stdlib.h>

uint8_t g(uint8_t a, uint8_t b, uint8_t x){ uint8_t t=(a+b+x)&0xFF; return ((t<<2)|(t>>6))&0xFF; }
uint32_t f(uint32_t inp){
  uint8_t x[4]; uint32_t v=inp;
  for(int i=0;i<4;i++){x[i]=v&0xFF;v>>=8;}
  uint8_t y[4];
  y[2]=g(x[3]^x[2],x[1]^x[0],1);
  y[3]=g(x[3],y[2],0);
  y[1]=g(x[1]^x[0],y[2],0);
  y[0]=g(x[0],y[1],1);
  uint32_t out=0;
  for(int i=0;i<4;i++) out|=((uint32_t)y[i])<<(8*i);
  return out;
}
int main(){
  uint32_t N=1<<20;
  uint32_t *in=malloc(N*4), *out=malloc(N*4);
  uint32_t r=12345;
  for(uint32_t i=0;i<N;i++){ r=r*1103515245u+12345u; in[i]=r; out[i]=f(r); }
  // Known perfect relation
  { uint32_t im=0x01010101, om=1u<<18, cnt=0;
    for(uint32_t i=0;i<N;i++) if(__builtin_popcount(in[i]&im)%2 == __builtin_popcount(out[i]&om)%2) cnt++;
    printf("KNOWN in=0x%08x out=0x%08x frac=%.6f\n", im, om, (double)cnt/N-0.5);
  }
  // Search interesting masks: for each byte, bits 0-7; combine bit0 and bit2 of each byte etc.
  // But keep it manageable: test all 32 single-bit input masks, all 32 single-bit output masks
  // and multi-bit masks built from bit0/bit2 of each byte.
  // Precompute parity vectors for all candidate masks
  uint32_t input_bits[8]={0,2,8,10,16,18,24,26};
  uint32_t in_masks[256]; int n_in=0;
  for(int sub=0;sub<256;sub++){
    uint32_t m=0;
    for(int b=0;b<8;b++) if(sub&(1<<b)) m|=1<<input_bits[b];
    in_masks[n_in++]=m;
  }
  printf("Testing %d input masks x 32 output bits, N=%u\n", n_in, N);
  for(int imi=0; imi<n_in; imi++){
    uint32_t im=in_masks[imi];
    for(int ob=0;ob<32;ob++){
      uint32_t om=1u<<ob;
      uint32_t cnt=0;
      for(uint32_t i=0;i<N;i++){
        if(__builtin_popcount(in[i]&im)%2 == __builtin_popcount(out[i]&om)%2) cnt++;
      }
      double frac=(double)cnt/N-0.5;
      if(frac>0.24 || frac<-0.24){
        printf("in=0x%08x out_bit=%d om=0x%08x frac=%.4f\n", im, ob, om, frac);
      }
    }
  }
  return 0;
}
